const raw = $input.first().json;
const body = raw.body !== undefined ? raw.body : raw;

if (!body.entry?.[0]?.changes?.[0]?.value?.messages?.[0]) {
  return [{ json: { skip: true } }];
}

const change = body.entry[0].changes[0].value;
const message = change.messages[0];
const contact = change.contacts?.[0];

if (message.type !== 'text') {
  return [{ json: { skip: true, reason: 'non-text', from: message.from } }];
}

return [{
  json: {
    skip: false,
    wa_phone: message.from,
    wa_message_id: message.id,
    customer_name: contact?.profile?.name || 'Cliente',
    message_text: message.text.body,
    timestamp: message.timestamp
  }
}];

const msg = $node['Extract Message'].json;
const conv = $node['Upsert Conversation'].json[0];
const customer = $node['Upsert Customer'].json[0];

return [{
  json: {
    chatInput: msg.message_text,
    sessionId: msg.wa_phone,
    wa_phone: msg.wa_phone,
    customer_name: msg.customer_name,
    conversation_id: conv.id,
    customer_id: customer.id
  }
}];

// query = término de búsqueda del producto
const term = encodeURIComponent(query.trim());
const results = await $helpers.httpRequest({
  method: 'GET',
  url: `${$env.SUPABASE_URL}/rest/v1/products?or=(name.ilike.*${term}*,description.ilike.*${term}*)&is_active=eq.true&select=id,dropi_product_id,name,description,price,stock&limit=5`,
  headers: {
    apikey: $env.SUPABASE_SERVICE_KEY,
    Authorization: `Bearer ${$env.SUPABASE_SERVICE_KEY}`
  }
});

if (!results || results.length === 0) {
  return 'No encontré productos con ese criterio. Sugiere al cliente otro término de búsqueda.';
}

const lines = results.map(p =>
  `• ${p.name} | $${Number(p.price).toLocaleString('es-CO')} COP | Stock: ${p.stock} | ID: ${p.dropi_product_id}`
);
return `Productos encontrados:\n${lines.join('\n')}`;

let data;
try { data = JSON.parse(query); } catch(e) { return `Error: el input debe ser JSON válido. Recibido: ${query}`; }

const { customer_name, customer_phone, address, city, department, items, is_cod, conversation_id, customer_id } = data;

if (!items || !Array.isArray(items) || items.length === 0) {
  return 'Error: se requiere al menos un item en el pedido.';
}

const total_amount = items.reduce((sum, item) => sum + (Number(item.unit_price) * Number(item.quantity)), 0);

const orderRes = await $helpers.httpRequest({
  method: 'POST',
  url: `${$env.SUPABASE_URL}/rest/v1/orders`,
  headers: {
    apikey: $env.SUPABASE_SERVICE_KEY,
    Authorization: `Bearer ${$env.SUPABASE_SERVICE_KEY}`,
    'Content-Type': 'application/json',
    Prefer: 'return=representation'
  },
  body: JSON.stringify({
    customer_id,
    conversation_id,
    customer_name,
    customer_phone,
    shipping_address: address,
    city,
    department,
    items,
    is_cod: !!is_cod,
    total_amount,
    status: 'pending'
  })
});

const order = Array.isArray(orderRes) ? orderRes[0] : orderRes;

if (is_cod) {
  await $helpers.httpRequest({
    method: 'POST',
    url: 'https://api.resend.com/emails',
    headers: {
      Authorization: `Bearer ${$env.RESEND_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      from: $env.FROM_EMAIL,
      to: $env.INTERNAL_EMAIL,
      subject: `🛍️ Nuevo pedido CONTRA ENTREGA — ${customer_name}`,
      html: `<h2>Nuevo pedido contra entrega</h2><p><strong>Cliente:</strong> ${customer_name} | ${customer_phone}</p><p><strong>Dirección:</strong> ${address}, ${city}, ${department}</p><p><strong>Total:</strong> $${total_amount.toLocaleString('es-CO')} COP</p><p><strong>Pedido ID:</strong> ${order.id}</p>`
    })
  }).catch(() => null); // no bloquear si falla el email
}

return JSON.stringify({ order_id: order.id, total_amount: order.total_amount, is_cod: order.is_cod, status: order.status });

let data;
try { data = JSON.parse(query); } catch(e) { return `Error: el input debe ser JSON válido. Recibido: ${query}`; }

const { order_id, amount, description } = data;

const mpRes = await $helpers.httpRequest({
  method: 'POST',
  url: 'https://api.mercadopago.com/checkout/preferences',
  headers: {
    Authorization: `Bearer ${$env.MP_ACCESS_TOKEN}`,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    items: [{
      title: description || 'Pedido Shopper Center',
      quantity: 1,
      unit_price: Number(amount),
      currency_id: 'COP'
    }],
    external_reference: order_id,
    notification_url: `${$env.WEBHOOK_URL}/webhook/mercadopago`,
    statement_descriptor: 'Shopper Center'
  })
});

const paymentLink = mpRes.init_point;

await $helpers.httpRequest({
  method: 'PATCH',
  url: `${$env.SUPABASE_URL}/rest/v1/orders?id=eq.${order_id}`,
  headers: {
    apikey: $env.SUPABASE_SERVICE_KEY,
    Authorization: `Bearer ${$env.SUPABASE_SERVICE_KEY}`,
    'Content-Type': 'application/json',
    Prefer: 'return=minimal'
  },
  body: JSON.stringify({ mp_preference_id: mpRes.id, payment_link: paymentLink, status: 'awaiting_payment' })
});

return JSON.stringify({ payment_link: paymentLink, mp_preference_id: mpRes.id });

// query = número de teléfono
const phone = query.trim().replace(/\D/g, '');

const results = await $helpers.httpRequest({
  method: 'GET',
  url: `${$env.SUPABASE_URL}/rest/v1/orders?customer_phone=eq.${encodeURIComponent(phone)}&select=id,status,total_amount,is_cod,city,created_at&order=created_at.desc&limit=3`,
  headers: {
    apikey: $env.SUPABASE_SERVICE_KEY,
    Authorization: `Bearer ${$env.SUPABASE_SERVICE_KEY}`
  }
});

if (!results || results.length === 0) {
  return 'No encontré pedidos para este número de teléfono.';
}

const statusMap = {
  pending: 'Pendiente',
  awaiting_payment: 'Esperando pago',
  paid: 'Pagado',
  shipped: 'Enviado',
  delivered: 'Entregado',
  cancelled: 'Cancelado',
  human_escalated: 'En revisión'
};

const lines = results.map(o =>
  `• ID: ${o.id.slice(0,8)}... | ${statusMap[o.status] || o.status} | $${Number(o.total_amount).toLocaleString('es-CO')} COP | ${o.city} | ${o.created_at.slice(0,10)}`
);
return `Tus pedidos recientes:\n${lines.join('\n')}`;

let data;
try { data = JSON.parse(query); } catch(e) { data = { reason: query, conversation_id: null }; }

const { reason, conversation_id } = data;

if (conversation_id) {
  await $helpers.httpRequest({
    method: 'PATCH',
    url: `${$env.SUPABASE_URL}/rest/v1/conversations?id=eq.${conversation_id}`,
    headers: {
      apikey: $env.SUPABASE_SERVICE_KEY,
      Authorization: `Bearer ${$env.SUPABASE_SERVICE_KEY}`,
      'Content-Type': 'application/json',
      Prefer: 'return=minimal'
    },
    body: JSON.stringify({ status: 'human_escalated' })
  });

  await $helpers.httpRequest({
    method: 'POST',
    url: 'https://api.resend.com/emails',
    headers: {
      Authorization: `Bearer ${$env.RESEND_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      from: $env.FROM_EMAIL,
      to: $env.INTERNAL_EMAIL,
      subject: '🙋 Cliente solicita atención humana — Shopper Center',
      html: `<h2>Escalación a agente humano</h2><p><strong>Conversación ID:</strong> ${conversation_id}</p><p><strong>Razón:</strong> ${reason}</p><p>Por favor contactar al cliente a la brevedad.</p>`
    })
  }).catch(() => null);
}

return 'Conversación escalada exitosamente. Un asesor del equipo te contactará pronto.';
